import React, { useState } from 'react';
import axios from 'axios';

export default function Register() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [message, setMessage] = useState('');

  const handleRegister = async (e) => {
    e.preventDefault();
    try {
      // Step 1: Register the User
      const registerResponse = await axios.post('http://localhost:5000/auth/register', {
        username,
        password,
        role: 'Employee', // Automatically set role to Employee
      });

      console.log('Register Response:', registerResponse.data);

      const userId = registerResponse.data.user_id;
      if (!userId) {
        throw new Error('User ID not received from registration API');
      }

      // Step 2: Fetch User Details
      const userResponse = await axios.get(`http://localhost:5000/auth/user/${userId}`);
      console.log('User Details:', userResponse.data);

      const name = userResponse.data.name;
      const dob = userResponse.data.dob;

      if (!name || !dob) {
        throw new Error('User details not found');
      }

      // Step 3: Create Employee
      const employeeResponse = await axios.post('http://localhost:5000/employees/create', {
        user_id: userId,
        name: name,
        dob: dob,
      });

      console.log('Employee Response:', employeeResponse.data);

      setMessage(`Registration successful! Employee Name: ${employeeResponse.data.name}, DOB: ${employeeResponse.data.dob}`);
    } catch (error) {
      console.error('Error:', error.response ? error.response.data : error.message);
      setMessage(`Registration failed: ${error.response ? error.response.data.message : error.message}`);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gray-100">
      <div className="bg-white p-6 rounded-lg shadow-lg w-96">
        <h2 className="text-2xl font-bold mb-4 text-center">Register</h2>
        {message && <p className="text-center text-red-500">{message}</p>}
        <form onSubmit={handleRegister} className="space-y-4">
          <div>
            <label className="block text-gray-700">Username</label>
            <input 
              type="text" 
              className="w-full px-3 py-2 border rounded-lg" 
              value={username} 
              onChange={(e) => setUsername(e.target.value)} 
              required 
            />
          </div>
          <div>
            <label className="block text-gray-700">Password</label>
            <input 
              type="password" 
              className="w-full px-3 py-2 border rounded-lg" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              required 
            />
          </div>
          <button 
            type="submit" 
            className="w-full bg-blue-500 text-white py-2 rounded-lg hover:bg-blue-600">
            Register
          </button>
        </form>
      </div>
    </div>
  );
}
